let jobs = [];
try {
  jobs = JSON.parse($input.first().json.stdout || '[]');
  if (!Array.isArray(jobs)) jobs = [];
} catch {
  jobs = [];
}
const seen = new Set();
const deduped = jobs.filter((job) => {
  const key = String(job.id || `${job.company?.name || ''}-${job.position || ''}`);
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});
return deduped.map((job) => ({ json: job }));

const jobs = $input.all();
const total = jobs.length;
const top = jobs.slice(0, 10);
const nowKst = `${new Intl.DateTimeFormat('sv-SE', {
  timeZone: 'Asia/Seoul',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit',
  hour12: false
}).format(new Date()).replace(' ', 'T')}+09:00`;
const lines = ['🔍 Wanted Job Alert', '', `총 ${total}개 신규 공고 발견`];
for (const item of top) {
  const j = item.json;
  lines.push('');
  lines.push(`💼 ${j.position || 'Unknown Position'}`);
  lines.push(`🏢 ${j.company?.name || 'Unknown Company'}`);
  lines.push(`🔗 https://www.wanted.co.kr/wd/${j.id}`);
}
lines.push('');
lines.push(`🕒 검색 시각: ${nowKst}`);
return [{ json: { text: lines.join('\n').slice(0, 3000) } }];

const body = $input.first().json.body || $input.first().json;
const event = body.event || 'unknown';
const timestamp = body.timestamp || new Date().toISOString();
const platforms = body.platforms || {};
const actions = body.actions || {};
const validPlatforms = Object.entries(platforms).filter(([_, v]) => v.valid).map(([k]) => k);
const invalidPlatforms = Object.entries(platforms).filter(([_, v]) => !v.valid).map(([k]) => k);
const totalCookies = Object.values(platforms).reduce((sum, p) => sum + (p.cookies || 0), 0);
return [{ json: {
  isSuccess: validPlatforms.length > 0,
  status: validPlatforms.length > 0 ? 'completed' : 'failed',
  channel: 'automation-runner',
  command: `auto-all (${[actions.extract && 'extract', actions.sync && 'sync', actions.verify && 'verify'].filter(Boolean).join('+')})`,
  duration: 0,
  source: 'auto-all.js',
  errorMessage: invalidPlatforms.length > 0 ? `Invalid sessions: ${invalidPlatforms.join(', ')}` : null,
  outputUrl: null,
  validPlatforms: validPlatforms.join(', '),
  invalidPlatforms: invalidPlatforms.join(', '),
  totalCookies,
  event,
  timestamp
} }];

